 0  0  0\nINCAR\n#Basic parameters\nISMEAR\n= 0\nSIGMA\n= 0.1\nLREAL\n= Auto\nISYM\n= -1\nNELM\n= 100\nEDIFF\n= 1E-4\nLWAVE\n= .FALSE.\nLCHARG\n= .FALSE.

